import express from "express";
import path from "path";
import fs from "fs";
import { createServer as createViteServer } from "vite";
import cors from "cors";
import { GoogleGenAI, Modality } from "@google/genai";

async function startServer() {
  const app = express();
  const PORT = 3000;

  app.use(cors());
  app.use(express.json({ limit: "50mb" }));

  const getAI = () => {
    const apiKey = process.env.GEMINI_API_KEY || process.env.API_KEY;
    if (!apiKey) {
      throw new Error("GEMINI_API_KEY is not defined in environment variables");
    }
    return new GoogleGenAI({
      apiKey,
      httpOptions: {
        headers: {
          "User-Agent": "aistudio-build",
        },
      },
    });
  };

  async function fetchImageAsBase64(imageUrl: string): Promise<{ base64: string; mimeType: string } | null> {
    if (!imageUrl) return null;
    
    // 1. If it's already a data URL
    if (imageUrl.startsWith("data:")) {
      const parts = imageUrl.split(",");
      const meta = parts[0];
      const base64 = parts[1] || parts[0];
      let mimeType = "image/jpeg";
      if (meta.includes("image/png")) mimeType = "image/png";
      else if (meta.includes("image/webp")) mimeType = "image/webp";
      else if (meta.includes("image/gif")) mimeType = "image/gif";
      return { base64, mimeType };
    }

    // 2. If it's a remote URL starting with http/https
    if (imageUrl.startsWith("http://") || imageUrl.startsWith("https://")) {
      try {
        const response = await fetch(imageUrl);
        if (!response.ok) return null;
        const arrayBuffer = await response.arrayBuffer();
        const buffer = Buffer.from(arrayBuffer);
        const base64 = buffer.toString("base64");
        const contentType = response.headers.get("content-type") || "image/jpeg";
        return { base64, mimeType: contentType };
      } catch (e) {
        console.warn("Error fetching remote image URL in fetchImageAsBase64:", imageUrl, e);
        return null;
      }
    }

    // 3. If it is a local relative URL path (e.g. /uploads/image.png or images/char.jpg or /avatars/...)
    try {
      const cleanPath = imageUrl.startsWith("/") ? imageUrl.substring(1) : imageUrl;
      // Check in root directory or public/
      let localPath = path.join(process.cwd(), cleanPath);
      if (!fs.existsSync(localPath)) {
        localPath = path.join(process.cwd(), "public", cleanPath);
      }
      
      if (fs.existsSync(localPath)) {
        const buffer = fs.readFileSync(localPath);
        const base64 = buffer.toString("base64");
        let mimeType = "image/jpeg";
        if (cleanPath.endsWith(".png")) mimeType = "image/png";
        else if (cleanPath.endsWith(".webp")) mimeType = "image/webp";
        else if (cleanPath.endsWith(".gif")) mimeType = "image/gif";
        return { base64, mimeType };
      }
    } catch (e) {
      console.warn("Error reading local image file in fetchImageAsBase64:", imageUrl, e);
    }

    return null;
  }

  // API endpoints:
  app.post("/api/gemini/chat", async (req, res) => {
    try {
      const { message, history } = req.body;
      const ai = getAI();
      const chat = ai.chats.create({
        model: "gemini-3.5-flash",
        history: history,
        config: {
          systemInstruction: "You are a helpful, witty, and highly intelligent AI assistant called Gemini Hub. You provide concise but deep insights.",
          tools: [{ googleSearch: {} }],
        },
      });
      const response = await chat.sendMessage({ message });
      res.json({
        text: response.text || "No response received.",
        sources: response.candidates?.[0]?.groundingMetadata?.groundingChunks?.map((chunk: any) => ({
          title: chunk.web?.title || "Source",
          uri: chunk.web?.uri || "#",
        })) || [],
      });
    } catch (err: any) {
      console.error(err);
      res.status(500).json({ error: err.message || "Unknown error" });
    }
  });

  app.post("/api/gemini/analyze-image", async (req, res) => {
    try {
      const { prompt, base64Image } = req.body;
      const ai = getAI();
      const response = await ai.models.generateContent({
        model: "gemini-3.5-flash",
        contents: {
          parts: [
            { inlineData: { mimeType: "image/jpeg", data: base64Image } },
            { text: prompt },
          ],
        },
      });
      res.json({ text: response.text });
    } catch (err: any) {
      console.error(err);
      res.status(500).json({ error: err.message || "Unknown error" });
    }
  });

  app.post("/api/gemini/generate-image", async (req, res) => {
    try {
      const { prompt, base64Image } = req.body;
      const ai = getAI();
      
      let contentsParts: any[] = [{ text: prompt }];
      
      if (base64Image) {
        const resolved = await fetchImageAsBase64(base64Image);
        if (resolved) {
          contentsParts.unshift({
            inlineData: {
              data: resolved.base64,
              mimeType: resolved.mimeType
            }
          });
        }
      }

      const response = await ai.models.generateContent({
        model: "gemini-2.5-flash-image",
        contents: { parts: contentsParts },
        config: {
          imageConfig: { aspectRatio: "1:1" },
        },
      });
      let imageData = null;
      for (const part of response.candidates?.[0]?.content?.parts || []) {
        if (part.inlineData) {
          imageData = `data:image/png;base64,${part.inlineData.data}`;
          break;
        }
      }
      if (!imageData) {
        throw new Error("No image data returned from model");
      }
      res.json({ imageUrl: imageData });
    } catch (err: any) {
      console.warn("Gemini Image API Error/Quota exceeded, applying curated fallback:", err);
      // Construct beautiful curated themed art as premium fallback to keep UI perfectly working
      const lower = (req.body.prompt || "").toLowerCase();
      let fallbackUrl = "https://images.unsplash.com/photo-1579783900882-c0d3dad7b119?auto=format&fit=crop&w=600&h=600&q=80"; // classic portrait painting
      
      if (lower.includes("cyber") || lower.includes("neon") || lower.includes("tech") || lower.includes("city")) {
        fallbackUrl = "https://images.unsplash.com/photo-1563089145-599997674d42?auto=format&fit=crop&w=600&h=600&q=80";
      } else if (lower.includes("magic") || lower.includes("spell") || lower.includes("forest") || lower.includes("enchanted")) {
        fallbackUrl = "https://images.unsplash.com/photo-1519074069444-1ba4e6664104?auto=format&fit=crop&w=600&h=600&q=80";
      } else if (lower.includes("pixel") || lower.includes("8bit") || lower.includes("16bit") || lower.includes("game")) {
        fallbackUrl = "https://images.unsplash.com/photo-1550745165-9bc0b252726f?auto=format&fit=crop&w=600&h=600&q=80";
      } else if (lower.includes("dark") || lower.includes("shadow") || lower.includes("abyss") || lower.includes("death")) {
        fallbackUrl = "https://images.unsplash.com/photo-1618005182384-a83a8bd57fbe?auto=format&fit=crop&w=600&h=600&q=80";
      } else if (lower.includes("castle") || lower.includes("knight") || lower.includes("war") || lower.includes("battle")) {
        fallbackUrl = "https://images.unsplash.com/photo-1599831013473-c6aa741f237f?auto=format&fit=crop&w=600&h=600&q=80";
      }
      
      res.json({ 
        imageUrl: fallbackUrl,
        isFallback: true,
        warning: "Превышена квота или ИИ временно перегружен. Включен режим демонстрации готовых артов!"
      });
    }
  });

  app.post("/api/gemini/search-grounding", async (req, res) => {
    try {
      const { query } = req.body;
      const ai = getAI();
      const response = await ai.models.generateContent({
        model: "gemini-3.5-flash",
        contents: query,
        config: {
          tools: [{ googleSearch: {} }],
        },
      });
      const sources = response.candidates?.[0]?.groundingMetadata?.groundingChunks?.map((chunk: any) => ({
        title: chunk.web?.title || "Reference",
        uri: chunk.web?.uri || "#",
      })) || [];
      res.json({ text: response.text, sources });
    } catch (err: any) {
      console.error(err);
      res.status(500).json({ error: err.message || "Unknown error" });
    }
  });

  app.post("/api/gemini/text-to-speech", async (req, res) => {
    try {
      const { text } = req.body;
      const ai = getAI();
      const response = await ai.models.generateContent({
        model: "gemini-3.1-flash-tts-preview",
        contents: [{ parts: [{ text }] }],
        config: {
          responseModalities: [Modality.AUDIO],
          speechConfig: {
            voiceConfig: {
              prebuiltVoiceConfig: { voiceName: "Kore" },
            },
          },
        },
      });
      const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
      if (!base64Audio) throw new Error("Audio generation failed");
      res.json({ base64Audio });
    } catch (err: any) {
      console.error(err);
      res.status(500).json({ error: err.message || "Unknown error" });
    }
  });

  app.post("/api/gemini/describe-character-art", async (req, res) => {
    try {
      const { char, base64Image } = req.body;
      const ai = getAI();
      
      const resolved = await fetchImageAsBase64(base64Image || char.imageUrl);
      if (resolved) {
        const cleanBase64 = resolved.base64;
        const mimeType = resolved.mimeType;

        const prompt = `Подробно опиши внешность, позу, одежду, цвета, фон и художественный стиль персонажа на этом арте. Напиши захватывающее художественное описание (3–5 предложений) на русском языке. 
        Критически важное правило: ни в коем случае НЕ упоминай имя персонажа "${char.name}", его возраст, его фракцию или любое другое прямое указание на его личность.
        Начни описание сразу, без вводных фраз вроде "На этой картинке изображен..." или "На рисунке мы видим...".`;

        const response = await ai.models.generateContent({
          model: "gemini-3.5-flash",
          contents: {
            parts: [
              { inlineData: { mimeType, data: cleanBase64 } },
              { text: prompt },
            ],
          },
        });
        res.json({ text: response.text || "" });
      } else {
        const infoSummary = `Имя персонажа: ${char.name}
Описание/Биография: ${char.additionalInfo || ""}
Теги: ${char.tags?.join(", ") || ""} ${char.hiddenTags?.join(", ") || ""}
Возраст: ${char.age || ""}
Рост: ${char.height || ""}
Характеристики/детали: ${char.customFields?.map((f: any) => `${f.name}: ${f.value}`).join("; ") || ""}`;

        const prompt = `Пожалуйста, изучи информацию о персонаже:
        ${infoSummary}
        
        На основе данной информации придумай и напиши детальное художественное описание (3–5 предложений) для его официального концепт-арта/иллюстрации на русском языке. Опиши, как этот персонаж должен выглядеть на своем арте: его внешность, одежду, цветовую гамму, выражение лица, окружение, позу и атмосферу. 
        Критически важное правило: ни в коем случае НЕ упоминай имя персонажа "${char.name}", его возраст, его фракцию или любое прямое текстовое указание на его личность. Описание должно быть написано так, будто ты смотришь на уже готовый арт этого персонажа.
        Начни художественное описание сразу, без вводных фраз вроде "На этом концепт-арте..." или "На рисунке представлен...".`;

        const response = await ai.models.generateContent({
          model: "gemini-3.5-flash",
          contents: prompt,
        });
        res.json({ text: response.text || "" });
      }
    } catch (err: any) {
      console.warn("Gemini Character Description Error, using high-fidelity fallback:", err);
      try {
        const { char } = req.body;
        const cleanName = char?.name || "герой";
        const rawBio = char?.additionalInfo || "";
        
        // Ensure name is never revealed in full text fallback
        let bioSnippet = rawBio;
        if (cleanName && bioSnippet) {
          bioSnippet = bioSnippet.replace(new RegExp(cleanName, "gi"), "герой");
        }
        if (bioSnippet.length > 180) {
          bioSnippet = bioSnippet.substring(0, 180) + "...";
        }
        if (!bioSnippet) {
          bioSnippet = "окружен загадочной аурой величия и тайной силы, готовый раскрыть свое истинное мастерство";
        }

        const tagsLower = (char?.tags || []).map((t: string) => t.toLowerCase());
        const isMagical = tagsLower.some((t: string) => ["маг", "магия", "волшебство", "magic", "wizard", "колдун"].includes(t));
        const isTech = tagsLower.some((t: string) => ["тех", "кибер", "cyber", "neon", "робот", "robot", "tech"].includes(t));
        
        let themeContext = "эпических странствий и благородной борьбы";
        if (isMagical) {
          themeContext = "древних свитков заклинаний, загадочных звездных рун и мерцающего мистического сияния";
        } else if (isTech) {
          themeContext = "неонового сияния, передовых технологий и урбанистического будущего";
        }

        const fallbackText = `Статный и загадочный силуэт, плавно угадывающийся среди гармоничных полутонов света и тени. Облик превосходно передает атмосферу ${themeContext}. Взгляд устремлен вперед к далеким горизонтам, отражая железную волю и спокойную мудрость, а каждая деталь экипировки идеально завершает общую картину. Особый покрой одежд и акценты выдают глубокую предысторию: ${bioSnippet}.`;

        res.json({
          text: fallbackText,
          isFallback: true,
          warning: "ИИ перегружен. Активировано высококачественное тематическое описание."
        });
      } catch (fallbackErr) {
        res.json({
          text: "Фигура, пронизанная невероятным духом приключений, замерла в эффектной контрастной позе. Взгляд полон непоколебимой уверенности и таинственного блеска, перекликаясь с глубокими художественными фонами.",
          isFallback: true
        });
      }
    }
  });

  // Vite integration
  if (process.env.NODE_ENV !== "production") {
    const vite = await createViteServer({
      server: { middlewareMode: true },
      appType: "spa",
    });
    app.use(vite.middlewares);
  } else {
    const distPath = path.join(process.cwd(), "dist");
    app.use("/raz", express.static(distPath));
    app.use(express.static(distPath));
    app.get("*", (req, res) => {
      res.sendFile(path.join(distPath, "index.html"));
    });
  }

  app.listen(PORT, "0.0.0.0", () => {
    console.log(`Server running on http://localhost:${PORT}`);
  });
}

startServer();
